const items = $input.all();
const body = items[0].json.body;
const event = body.event;
const data = body.data;

// Validação do telefone
const telefone = (data.cliente_telefone_e164 || '').toString().trim();
const telefoneValido = /^55\d{2}9\d{8}$/.test(telefone);

if (!telefoneValido) {
  return [{ json: { telefone: '', mensagem: '', erro: 'Telefone inválido ou ausente: ' + (data.cliente_telefone || '(vazio)') + ' -> ' + telefone, enviar: false } }];
}

const nome = data.cliente_nome || 'Cliente';
const order = data.order_number || '';
const url = data.acompanhar_url || '';
const cupomUrl = data.cupom_url || url.replace('/acompanhar/', '/cupom/');
const avaliarUrl = data.avaliar_url || url.replace('/acompanhar/', '/avaliar/');
const total = data.total ? 'R$ ' + Number(data.total).toFixed(2).replace('.', ',') : '';
const pagamento = data.forma_pagamento || '';
const tipoEntrega = data.tipo_entrega || '';

const pagMap = { dinheiro: 'Dinheiro', cartao: 'Cartao', pix: 'PIX' };
const pagLabel = pagMap[pagamento] || pagamento;

let msg = '';

if (event === 'pedido.criado') {
  const tipo = tipoEntrega === 'retirada' ? 'Retirada no local' : 'Entrega';
  msg = '\ud83d\uded2 *Pedido Recebido!*\n\n'
    + 'Ola, ' + nome + '! Seu pedido *#' + order + '* foi recebido com sucesso!\n\n'
    + (total ? '\ud83d\udcb0 Total: *' + total + '*\n' : '')
    + (pagLabel ? '\ud83d\udcb3 Pagamento: ' + pagLabel + '\n' : '')
    + (tipo ? '\ud83d\udce6 Tipo: ' + tipo + '\n' : '')
    + '\nEm breve voce recebera a confirmacao do estabelecimento.\n\n'
    + '\ud83d\udccd Acompanhe seu pedido:\n' + url;

} else if (event === 'pedido.status.confirmado') {
  if (data.cupom_texto) {
    msg = data.cupom_texto;
    if (url) msg += '\n\n\ud83d\udccd Acompanhe seu pedido:\n' + url;
  } else {
    msg = '\u2705 *Pedido Confirmado!*\n\n'
      + 'Ola, ' + nome + '! Seu pedido *#' + order + '* foi confirmado com sucesso!\n\n'
      + (total ? '\ud83d\udcb0 Total: *' + total + '*\n\n' : '')
      + '\ud83d\udccd Acompanhe seu pedido:\n' + url;
  }

} else if (event === 'pedido.status.preparando') {
  msg = '\ud83d\udc68\u200d\ud83c\udf73 *Preparando seu Pedido!*\n\n'
    + 'Ola, ' + nome + '! Seu pedido *#' + order + '* esta sendo preparado com carinho.\n\n'
    + '\ud83d\udccd Acompanhe:\n' + url;

} else if (event === 'pedido.status.pronto') {
  msg = '\ud83d\udce6 *Pedido Pronto!*\n\n'
    + 'Ola, ' + nome + '! Seu pedido *#' + order + '* esta pronto! Aguardando entregador.\n\n'
    + '\ud83d\udccd Acompanhe:\n' + url;

} else if (event === 'pedido.status.saiu_entrega') {
  msg = '\ud83d\udef5 *Saiu para Entrega!*\n\n'
    + 'Ola, ' + nome + '! Seu pedido *#' + order + '* saiu para entrega!\n'
    + 'Em breve chegara ate voce.\n\n'
    + '\ud83d\udccd Acompanhe em tempo real:\n' + url;

} else if (event === 'pedido.status.entregue') {
  msg = '\u2705 *Pedido Entregue!*\n\n'
    + 'Ola, ' + nome + '! Seu pedido *#' + order + '* foi entregue com sucesso!\n\n'
    + 'Obrigado pela preferencia! \ud83d\ude4f\n\n'
    + '\u2b50 Avalie seu pedido:\n' + avaliarUrl;

} else if (event === 'pedido.status.cancelado') {
  msg = '\u274c *Pedido Cancelado*\n\n'
    + 'Ola, ' + nome + '. Infelizmente seu pedido *#' + order + '* foi cancelado.\n\n'
    + 'Se precisar de ajuda, entre em contato conosco.';

} else {
  msg = '\ud83d\udccb Atualizacao do pedido *#' + order + '*\n\n'
    + '\ud83d\udccd Acompanhe:\n' + url;
}

return [{ json: { telefone: telefone, mensagem: msg, enviar: true } }];
